"""PlatformIO upload wrapper.

Shells out to ``pio run -t upload`` in the given project directory. Picks an
upload port via :func:`atech.runtime.discover_ports` if none is supplied.
"""

from __future__ import annotations

import shutil
import subprocess
import time
from dataclasses import dataclass
from pathlib import Path
from typing import Optional

from atech.errors import UploadError
from atech.runtime.transport import discover_ports


@dataclass
class UploadResult:
    """Outcome of a PlatformIO upload."""

    project_dir: Path
    success: bool
    port: Optional[str]
    stdout: str
    stderr: str
    returncode: int


def _pio_executable() -> str:
    exe = shutil.which("pio") or shutil.which("platformio")
    if not exe:
        raise UploadError(
            "PlatformIO CLI not found on PATH. The 'atech' package declares it as a "
            "dependency — make sure you installed in the same environment."
        )
    return exe


def run_upload(
    project_dir: Path,
    *,
    port: Optional[str] = None,
    capture: bool = True,
    retries: int = 2,
    retry_delay: float = 2.0,
) -> UploadResult:
    """Flash the firmware in ``project_dir`` to a connected board.

    The ESP32-S3's native USB-CDC can briefly drop/re-enumerate (often while
    modules are being seated), which makes esptool hang at "Connecting...". We
    retry a few times so a transient drop doesn't fail the whole flash — each
    retry re-resolves the auto port in case the device path changed.
    """
    project_dir = Path(project_dir).expanduser().resolve()
    if not (project_dir / "platformio.ini").is_file():
        raise UploadError(
            f"no platformio.ini at {project_dir}. Run Project.generate() first."
        )

    pio = _pio_executable()
    last: Optional[subprocess.CompletedProcess] = None
    target_port = port
    for attempt in range(retries + 1):
        # Re-resolve the auto port each attempt (it can change on re-enumeration).
        resolved = target_port or _auto_port()
        cmd = [pio, "run", "-t", "upload", "-d", str(project_dir)]
        if resolved:
            cmd += ["--upload-port", resolved]
        proc = subprocess.run(cmd, capture_output=capture, text=True)
        last = proc
        if proc.returncode == 0:
            return UploadResult(
                project_dir=project_dir,
                success=True,
                port=resolved,
                stdout=proc.stdout or "",
                stderr=proc.stderr or "",
                returncode=0,
            )
        if attempt < retries:
            time.sleep(retry_delay)  # let the board settle / re-appear

    assert last is not None
    return UploadResult(
        project_dir=project_dir,
        success=False,
        port=target_port or _auto_port(),
        stdout=last.stdout or "",
        stderr=last.stderr or "",
        returncode=last.returncode,
    )


def _auto_port() -> Optional[str]:
    candidates = discover_ports()
    return candidates[0].device if candidates else None
